<template>
	<view class="container">
		<!-- йЎ¶йғЁж·»еҠ з”ЁжҲ·жҢүй’® -->
		<view class="header">
			<u-button 
				type="primary" 
				icon="plus" 
				@click="showAddUserPopup"
			>
				ж·»еҠ з”ЁжҲ·
			</u-button>
		</view>

		<!-- е…іжіЁеҲ—иЎЁ -->
		<scroll-view 
			scroll-y 
			class="list-container"
			@scrolltolower="loadMore"
		>
			<view v-if="followedList.length === 0" class="empty-tip">
				<u-icon name="account" size="80" color="#ccc"></u-icon>
				<text>жҡӮж— е…іжіЁзҡ„з”ЁжҲ·пјҢзӮ№еҮ»еҸідёҠи§’ж·»еҠ з”ЁжҲ·еҗ§~</text>
			</view>

			<view 
				v-for="(user, index) in followedList" 
				:key="user.id"
				class="user-item"
			>
				<!-- зӮ№еҮ»з”ЁжҲ·дҝЎжҒҜеҢәеҹҹиҝӣе…ҘиҒҠеӨ© -->
				<view class="user-info-area" @click="goToChat(user)">
					<u-avatar 
						:src="user.avatar || '/static/logo.png'" 
						size="60"
					></u-avatar>
					<view class="user-info">
						<text class="nickname">{{ user.nickname }}</text>
						<text class="bio" v-if="user.bio">{{ user.bio }}</text>
					</view>
				</view>
				
				<!-- еҸ–е…іжҢүй’® -->
				<view class="unfollow-btn" @click.stop="unfollowUser(user)">
					<u-icon name="close-circle" color="#ff4d4f" size="24"></u-icon>
				</view>
			</view>
		</scroll-view>

		<!-- ж·»еҠ з”ЁжҲ·еј№зӘ— -->
		<u-popup 
			:show="showPopup" 
			mode="center" 
			round="20"
			@click-overlay="closePopup"
		>
			<view class="popup-content">
				<view class="popup-header">
					<text class="title">жҗңзҙўз”ЁжҲ·</text>
					<u-icon 
						name="close" 
						size="24" 
						color="#999"
						@click="closePopup"
					></u-icon>
				</view>

				<!-- жҗңзҙўжЎҶ -->
				<view class="search-box">
					<u-search 
						v-model="searchKeyword" 
						placeholder="иҜ·иҫ“е…Ҙжҳөз§°жҗңзҙў"
						:show-action="false"
						@search="handleSearch"
						@custom="handleSearch"
					></u-search>
				</view>

				<!-- жҗңзҙўз»“жһң -->
				<scroll-view scroll-y class="search-result">
					<view v-if="isSearched && searchResults.length === 0" class="no-result">
						<text>жңӘжүҫеҲ°зӣёе…із”ЁжҲ·</text>
					</view>

					<view 
						v-for="user in searchResults" 
						:key="user.id"
						class="result-item"
					>
						<u-avatar 
							:src="user.avatar || '/static/logo.png'" 
							size="50"
						></u-avatar>
						<view class="result-info">
							<text class="nickname">{{ user.nickname }}</text>
							<text class="bio" v-if="user.bio">{{ user.bio }}</text>
						</view>
						<u-icon 
							v-if="!isFollowed(user.id)"
							name="plus-circle" 
							size="28" 
							color="#2867CE"
							@click.stop="followUser(user)"
							class="follow-icon"
						></u-icon>
						<u-icon 
							v-else
							name="checkmark-circle" 
							size="28" 
							color="#999"
							class="followed-icon"
						></u-icon>
					</view>
				</scroll-view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				followedList: [], // е·Іе…іжіЁзҡ„з”ЁжҲ·еҲ—иЎЁ
				showPopup: false, // жҳҜеҗҰжҳҫзӨәеј№зӘ—
				searchKeyword: '', // жҗңзҙўе…ій”®иҜҚ
				searchResults: [], // жҗңзҙўз»“жһң
				isSearched: false, // жҳҜеҗҰе·Іжҗңзҙў
				// жЁЎжӢҹзҡ„з”ЁжҲ·ж•°жҚ®еә“пјҲе®һйҷ…еә”иҜҘд»Һдә‘ж•°жҚ®еә“иҺ·еҸ–пјү
				mockUsers: [
					{ id: 1, nickname: 'еј дёү', avatar: '', bio: 'е–ңж¬ўзј–зЁӢе–ңж¬ўзј–зЁӢе–ңж¬ўзј–зЁӢе–ңж¬ўзј–зЁӢе–ңж¬ўзј–зЁӢ' },
					{ id: 2, nickname: 'жқҺеӣӣ', avatar: '', bio: 'еүҚз«Ҝе·ҘзЁӢеёҲ' },
					{ id: 3, nickname: 'зҺӢдә”', avatar: '', bio: 'е…Ёж ҲејҖеҸ‘' },
					{ id: 4, nickname: 'иөөе…ӯ', avatar: '', bio: 'UIи®ҫи®ЎеёҲ' },
					{ id: 5, nickname: 'е°ҸжҳҺ', avatar: '', bio: 'дә§е“Ғз»ҸзҗҶ' }
				]
			};
		},
		onShow() {
			// йЎөйқўжҳҫзӨәж—¶еҠ иҪҪе…іжіЁеҲ—иЎЁ
			this.loadFollowedList();
		},
		methods: {
			// иҺ·еҸ–дјҡиҜқIDпјҲз»ҹдёҖдҪҝз”Ё currentSessionIdпјү
			getSessionId() {
				let sessionId = uni.getStorageSync('currentSessionId');
				
				if (!sessionId) {
					sessionId = 'user_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
					uni.setStorageSync('currentSessionId', sessionId);
					console.log('з”ҹжҲҗж–°дјҡиҜқID:', sessionId);
				}
				
				return sessionId;
			},
			
			// еҠ иҪҪе…іжіЁеҲ—иЎЁпјҲжҢүдјҡиҜқйҡ”зҰ»пјү
			loadFollowedList() {
                const sessionId = this.getSessionId();
                const followedKey = `followedList_${sessionId}`;
                
                const followed = uni.getStorageSync(followedKey);
                console.log('еҠ иҪҪе…іжіЁеҲ—иЎЁпјҢsession:', sessionId, 'ж•°йҮҸ:', followed ? followed.length : 0);
                
                if (followed) {
                    this.followedList = followed;
                } else {
                    this.followedList = [];
                }
            },

			// жҳҫзӨәж·»еҠ з”ЁжҲ·еј№зӘ—
			showAddUserPopup() {
				this.showPopup = true;
				this.searchKeyword = '';
				this.searchResults = [];
				this.isSearched = false;
			},

			// е…ій—ӯеј№зӘ—
			closePopup() {
				this.showPopup = false;
			},

			// еӨ„зҗҶжҗңзҙў
			handleSearch() {
				if (!this.searchKeyword.trim()) {
					uni.showToast({
						title: 'иҜ·иҫ“е…Ҙжҗңзҙўе…ій”®иҜҚ',
						icon: 'none'
					});
					return;
				}

				this.isSearched = true;
				
				// жЁЎжӢҹжҗңзҙўпјҡд»Һ mockUsers дёӯиҝҮж»Ө
				// е®һйҷ…йЎ№зӣ®дёӯеә”иҜҘи°ғз”Ёдә‘еҮҪж•°жҲ– API
				this.searchResults = this.mockUsers.filter(user => 
					user.nickname.includes(this.searchKeyword)
				);

				if (this.searchResults.length === 0) {
					uni.showToast({
						title: 'жңӘжүҫеҲ°зӣёе…із”ЁжҲ·',
						icon: 'none'
					});
				}
			},

			// еҲӨж–ӯжҳҜеҗҰе·Іе…іжіЁ
			isFollowed(userId) {
				return this.followedList.some(user => user.id === userId);
			},

			// е…іжіЁз”ЁжҲ·
			followUser(user) {
                const sessionId = this.getSessionId();
                
                // жЈҖжҹҘжҳҜеҗҰе·Іе…іжіЁ
                if (this.isFollowed(user.id)) {
                    uni.showToast({
                        title: 'е·Із»Ҹе…іжіЁиҝҮдәҶ',
                        icon: 'none'
                    });
                    return;
                }

                // ж·»еҠ еҲ°е…іжіЁеҲ—иЎЁ
                this.followedList.push({
                    id: user.id,
                    nickname: user.nickname,
                    avatar: user.avatar,
                    bio: user.bio
                });

                // дҝқеӯҳеҲ°жң¬ең°еӯҳеӮЁпјҲжҢүдјҡиҜқйҡ”зҰ»пјү
                try {
                    const followedKey = `followedList_${sessionId}`;
                    uni.setStorageSync(followedKey, this.followedList);
                    console.log('е…іжіЁжҲҗеҠҹпјҢsession:', sessionId, 'followed:', user.nickname);
                    
                    uni.showToast({
                        title: 'е…іжіЁжҲҗеҠҹ',
                        icon: 'success'
                    });

                    // д»Һжҗңзҙўз»“жһңдёӯз§»йҷӨпјҲеҸҜйҖүпјү
                    this.searchResults = this.searchResults.filter(u => u.id !== user.id);
                } catch (error) {
                    console.error('дҝқеӯҳеӨұиҙҘ:', error);
                    uni.showToast({
                        title: 'е…іжіЁеӨұиҙҘ',
                        icon: 'none'
                    });
                }
            },

			// еҸ–е…із”ЁжҲ·
			unfollowUser(user) {
				uni.showModal({
					title: 'жҸҗзӨә',
					content: `зЎ®е®ҡиҰҒеҸ–ж¶Ҳе…іжіЁ"${user.nickname}"еҗ—пјҹ`,
					success: (res) => {
						if (res.confirm) {
							this.performUnfollow(user.id);
						}
					}
				});
			},

			// жү§иЎҢеҸ–е…іж“ҚдҪң
			performUnfollow(userId) {
                const sessionId = this.getSessionId();
                
                try {
                    // д»ҺеҲ—иЎЁдёӯз§»йҷӨ
                    this.followedList = this.followedList.filter(user => user.id !== userId);
                    
                    // дҝқеӯҳеҲ°жң¬ең°еӯҳеӮЁпјҲжҢүдјҡиҜқйҡ”зҰ»пјү
                    const followedKey = `followedList_${sessionId}`;
                    uni.setStorageSync(followedKey, this.followedList);
                    console.log('еҸ–е…іжҲҗеҠҹпјҢsession:', sessionId);
                    
                    uni.showToast({
                        title: 'е·ІеҸ–ж¶Ҳе…іжіЁ',
                        icon: 'success'
                    });
                } catch (error) {
                    console.error('еҸ–е…іеӨұиҙҘ:', error);
                    uni.showToast({
                        title: 'еҸ–е…іеӨұиҙҘ',
                        icon: 'none'
                    });
                }
            },

			// и·іиҪ¬еҲ°иҒҠеӨ©йЎөйқў
			goToChat(user) {
				uni.navigateTo({
					url: `/pages/chat/chat?userId=${user.id}&nickname=${encodeURIComponent(user.nickname)}&avatar=${encodeURIComponent(user.avatar || '')}`
				});
			},

			// еҠ иҪҪжӣҙеӨҡпјҲйў„з•ҷеҲҶйЎөеҠҹиғҪпјү
			loadMore() {
				// TODO: е®һзҺ°еҲҶйЎөеҠ иҪҪ
				console.log('еҠ иҪҪжӣҙеӨҡ');
			}
		}
	};
</script>

